"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([[53],{1109:e=>{e.exports=JSON.parse('{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","label":"Intro","href":"/docs/intro","docId":"intro"},{"type":"category","label":"KDB/Q Language","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"KDB/Q Unveiled: A Journey into the Pinnacle of Database Technology","href":"/docs/language/history","docId":"language/history"},{"type":"link","label":"Unlocking Unmatched Performance: The Speed Secrets of KDB/Q","href":"/docs/language/speed","docId":"language/speed"}],"href":"/docs/category/kdbq-language"},{"type":"category","label":"KDB Architecture","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"The Plain Vanilla Tick Setup","href":"/docs/architecture/plain","docId":"architecture/plain"}],"href":"/docs/category/kdb-architecture"},{"type":"category","label":"Tutorials","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"KDB Tick Explained: A Walkthrough [PART 1]","href":"/docs/tutorials/tick","docId":"tutorials/tick"},{"type":"link","label":"KDB Tick Explained: A Walkthrough [PART 2]","href":"/docs/tutorials/tick2","docId":"tutorials/tick2"}],"href":"/docs/category/tutorials"}]},"docs":{"architecture/plain":{"id":"architecture/plain","title":"The Plain Vanilla Tick Setup","description":"A basic KDB/Q Tick setup consists of three  essential elements such as a Tickerplant (TP), a Real-Time Database (RDB), and a Historical Database (HDB). Additionally, this configuration involves the integration of two external processes, namely a Data Feed and a Feed Handler. The provided image below serves as a visual representation of this architectural arrangement.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Intro","description":"Before we can start learning KDB/Q we first need to have a running version of q installed. Let\'s kickstart our journey!","sidebar":"tutorialSidebar"},"language/history":{"id":"language/history","title":"KDB/Q Unveiled: A Journey into the Pinnacle of Database Technology","description":"In the ever-evolving landscape of programming languages, KDB/Q stands as a testament to innovation and efficiency. This post delves into the origins, evolution, and the ingenious mind behind KDB/Q, unraveling the layers that make it an exceptional database language.","sidebar":"tutorialSidebar"},"language/speed":{"id":"language/speed","title":"Unlocking Unmatched Performance: The Speed Secrets of KDB/Q","description":"In the world of time-series databases, KDB/Q stands as a powerhouse, setting itself apart with unparalleled performance and speed. At the core of its efficiency lies a combination of design principles and unique features that make it the preferred choice for industries dealing with massive datasets and demanding real-time analytics.","sidebar":"tutorialSidebar"},"tutorials/tick":{"id":"tutorials/tick","title":"KDB Tick Explained: A Walkthrough [PART 1]","description":"In this blog post, we\'re diving into the code of a simple Tickerplant. We\'ll break it down line by line, explaining what each part does and how it fits into the big picture. This will not only demystify Tickerplants but also shed light on important KDB/Q programming concepts. By doing so, you\'ll gain insights into the inner workings of a Tickerplant and acquire a deeper understanding of key concepts in the KDB/Q programming language.","sidebar":"tutorialSidebar"},"tutorials/tick2":{"id":"tutorials/tick2","title":"KDB Tick Explained: A Walkthrough [PART 2]","description":"In my previous tutorial I walked you through all the helper functions you can find in the u.q file of a plain vanilla Tickerplant. I provided a comprehensive overview of the inner workings of these functions and how they interact with each other. It is now time to circle back and continue with our step-by-step examination of the main tick.q file and complete complete our understanding of the Tickerplant. If you\'d like to revisit our previous discussions or if you\'re new to this tutorial, you can access my earlier post here.","sidebar":"tutorialSidebar"}}}')}}]);